// PATCH: Add local subscription detection from transaction cadence and amount stability.

type subscriptionResult struct {
	PayeeNormalized string  `json:"payee_normalized"`
	Occurrences     int     `json:"occurrences"`
	AvgAmount       float64 `json:"avg_amount"`
	Cadence         string  `json:"cadence"`
	LastSeen        string  `json:"last_seen"`
	AmountStddevPct float64 `json:"amount_stddev_pct"`
}

func newTransactionsSubscriptionsCmd(flags *rootFlags) *cobra.Command {
	var suspectedOnly bool
	var minOccurrences int
	var dbPath string

	cmd := &cobra.Command{
		Use:         "subscriptions",
		Short:       "Find local merchant charges with regular cadence",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: strings.Trim(`
  # Show tight monthly, weekly, or yearly merchant charge patterns
  lunch-money-pp-cli transactions subscriptions --suspected-only --json
  `, "\n"),
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			if minOccurrences < 2 {
				return usageErr(fmt.Errorf("--min-occurrences must be at least 2"))
			}
			db, err := openLocalStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("transactions subscriptions: %w", err)
			}
			defer db.Close()
			txs, err := loadLocalTransactions(cmd.Context(), db)
			if err != nil {
				return fmt.Errorf("transactions subscriptions: %w", err)
			}
			results := buildSubscriptionResults(txs, minOccurrences, suspectedOnly)
			w := cmd.OutOrStdout()
			if flags.asJSON {
				return json.NewEncoder(w).Encode(results)
			}
			fmt.Fprintln(w, "Payee\tOccurrences\tAvg Amount\tCadence\tLast Seen\tAmount Stddev Pct")
			for _, r := range results {
				fmt.Fprintf(w, "%s\t%d\t%.2f\t%s\t%s\t%.4f\n",
					r.PayeeNormalized, r.Occurrences, r.AvgAmount, r.Cadence, r.LastSeen, r.AmountStddevPct)
			}
			return nil
		},
	}

	cmd.Flags().BoolVar(&suspectedOnly, "suspected-only", false, "Only show groups with amount stddev <= 10%")
	cmd.Flags().IntVar(&minOccurrences, "min-occurrences", 3, "Minimum occurrences in a merchant group")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func buildSubscriptionResults(txs []localTransaction, minOccurrences int, suspectedOnly bool) []subscriptionResult {
	groups := map[string][]localTransaction{}
	for _, tx := range txs {
		if tx.PayeeNormalized == "" || tx.Date.IsZero() || !subscriptionCountsTransaction(tx) {
			continue
		}
		groups[tx.PayeeNormalized] = append(groups[tx.PayeeNormalized], tx)
	}

	results := make([]subscriptionResult, 0)
	for payee, group := range groups {
		if len(group) < minOccurrences || groupHasRecurring(group) {
			continue
		}
		amounts := make([]float64, 0, len(group))
		dates := make([]time.Time, 0, len(group))
		lastSeen := group[0]
		for _, tx := range group {
			amounts = append(amounts, tx.Amount)
			dates = append(dates, tx.Date)
			if tx.Date.After(lastSeen.Date) {
				lastSeen = tx
			}
		}
		avg := localMean(amounts)
		cadence := inferLocalCadence(dates)
		if avg <= 0 || cadence == "" {
			continue
		}
		stddevPct := localStddevPct(amounts)
		if suspectedOnly && stddevPct > 0.10 {
			continue
		}
		results = append(results, subscriptionResult{
			PayeeNormalized: payee,
			Occurrences:     len(group),
			AvgAmount:       avg,
			Cadence:         cadence,
			LastSeen:        lastSeen.DateString,
			AmountStddevPct: stddevPct,
		})
	}
	sort.SliceStable(results, func(i, j int) bool {
		if results[i].LastSeen == results[j].LastSeen {
			return results[i].PayeeNormalized < results[j].PayeeNormalized
		}
		return results[i].LastSeen > results[j].LastSeen
	})
	return results
}

func subscriptionCountsTransaction(tx localTransaction) bool {
	// PATCH(exclude-status): Lunch Money's exclude status removes a row from
	// budget and reporting calculations; mirror that here so excluded
	// transactions cannot pollute the inter-charge cadence inference.
	if strings.EqualFold(tx.Status, "exclude") || strings.EqualFold(tx.Status, "excluded") {
		return false
	}
	return tx.SplitParentID == "" && tx.GroupParentID == "" && !tx.IsSplitParent && !tx.IsGroupParent
}

func groupHasRecurring(group []localTransaction) bool {
	for _, tx := range group {
		if tx.RecurringID != "" {
			return true
		}
	}
	return false
}
